import { useEffect, useRef, useState } from "react";
import "./ScrollGallery.css";

const images = [
  "/assets/img/gallery/IMG_2385.JPG.jpeg",
  "/assets/img/gallery/Firefly 20241104105047.png",
  "/assets/img/gallery/01_Group Photo Edited_1.jpg",
  "/assets/img/gallery/WhatsApp Image 2024-11-21 at 1.40.54 PM.jpeg",
  "/assets/img/gallery/WhatsApp Image 2024-11-21 at 3.05.40 PM (1).jpeg",
  "/assets/img/gallery/WhatsApp Image 2024-11-21 at 3.05.42 PM.jpeg",
  "/assets/img/gallery/WhatsApp Image 2024-11-21 at 3.05.48 PM (1).jpeg",
  "/assets/img/gallery/WhatsApp Image 2024-11-21 at 3.05.48 PM.jpeg",
  "/assets/img/gallery/WhatsApp Image 2024-11-21 at 3.05.50 PM.jpeg",
  "/assets/img/gallery/WhatsApp Image 2024-11-21 at 3.05.51 PM (1).jpeg",
];

const ScrollGallery = () => {
  const sectionRef = useRef(null);
  const [active, setActive] = useState(0);
  const [progress, setProgress] = useState(0);

  // Use refs so the wheel handler always reads fresh values
  const lockedRef = useRef(false);
  const activeRef = useRef(0);
  const scrollAcc = useRef(0);

  // Keep activeRef in sync with state
  useEffect(() => {
    activeRef.current = active;
    setProgress(active / (images.length - 1));
  }, [active]);

  // Attach the wheel listener ONCE — reads refs, never goes stale
  useEffect(() => {
    const onWheel = (e) => {
      if (!lockedRef.current) return;

      // Block the page from scrolling
      e.preventDefault();
      e.stopPropagation();

      scrollAcc.current += e.deltaY;
      const current = activeRef.current;

      if (scrollAcc.current > 120 && current < images.length - 1) {
        setActive(current + 1);
        scrollAcc.current = 0;
        return;
      }

      if (scrollAcc.current < -120 && current > 0) {
        setActive(current - 1);
        scrollAcc.current = 0;
        return;
      }

      // Unlock only after the last image and an extra intentional scroll
      if (current === images.length - 1 && scrollAcc.current > 200) {
        lockedRef.current = false;
        document.body.classList.remove("scroll-lock");
        scrollAcc.current = 0;
      }
    };

    window.addEventListener("wheel", onWheel, { passive: false });
    return () => window.removeEventListener("wheel", onWheel);
  }, []); // empty deps — safe because we use refs

  // Lock when section enters viewport
  useEffect(() => {
    const section = sectionRef.current;

    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting && !lockedRef.current) {
          scrollAcc.current = 0;
          lockedRef.current = true;
          document.body.classList.add("scroll-lock");
        }
      },
      { threshold: 0.6 },
    );

    observer.observe(section);
    return () => observer.disconnect();
  }, []);

  return (
    <section ref={sectionRef} className="scroll-gallery-enhanced">
      {/* Enhanced Background */}
      <div className="gallery-bg-enhanced">
        <div
          className="bg-gradient gradient-1"
          style={{
            transform: `translate(${progress * 100}px, ${progress * 80}px) scale(${1 + progress * 0.3})`,
          }}
        />
        <div
          className="bg-gradient gradient-2"
          style={{
            transform: `translate(${-progress * 120}px, ${progress * 60}px) scale(${1 + progress * 0.2})`,
          }}
        />
        <div
          className="bg-gradient gradient-3"
          style={{
            transform: `translate(${progress * 80}px, ${-progress * 100}px) scale(${1 + progress * 0.25})`,
          }}
        />

        {/* Particle Effect */}
        <div className="particles">
          {[...Array(20)].map((_, i) => (
            <div
              key={i}
              className="particle"
              style={{
                left: `${Math.random() * 100}%`,
                top: `${Math.random() * 100}%`,
                animationDelay: `${Math.random() * 5}s`,
                animationDuration: `${5 + Math.random() * 10}s`,
              }}
            />
          ))}
        </div>
      </div>

      {/* Gallery Info */}
      <div className="gallery-info">
        <div className="info-counter">
          <span className="counter-current">
            {String(active + 1).padStart(2, "0")}
          </span>
          <span className="counter-divider">/</span>
          <span className="counter-total">
            {String(images.length).padStart(2, "0")}
          </span>
        </div>

        <div className="info-progress">
          <div
            className="progress-bar"
            style={{ width: `${((active + 1) / images.length) * 100}%` }}
          />
        </div>

        <p className="info-instruction">
          {active === images.length - 1 ? "Scroll again to continue" : "Scroll to explore"}
        </p>
      </div>

      {/* Gallery Stage */}
      <div className="gallery-stage-enhanced">
        {images.map((src, i) => {
          const offset = i - active;
          const isActive = i === active;
          const distance = Math.abs(offset);

          return (
            <div
              key={i}
              className={`gallery-card ${isActive ? "active" : ""}`}
              style={{
                transform: `
                  translateX(${offset * 160}px)
                  translateZ(${isActive ? 0 : -distance * 200}px)
                  scale(${isActive ? 1 : 0.7 - distance * 0.1})
                  rotateY(${offset * 20}deg)
                `,
                opacity: distance > 2 ? 0 : 1 - distance * 0.25,
                zIndex: 10 - distance,
              }}
            >
              <div className="card-shine" />
              <div className="card-border" />
              <img src={src} alt={`Project ${i + 1}`} />

              {isActive && (
                <div className="card-label">
                  <span>Project {i + 1}</span>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* Navigation Dots */}
      <div className="gallery-dots">
        {images.map((_, i) => (
          <button
            key={i}
            className={`dot ${i === active ? "active" : ""}`}
            onClick={() => setActive(i)}
            aria-label={`Go to image ${i + 1}`}
          />
        ))}
      </div>
    </section>
  );
};

export default ScrollGallery;
